class Solution:
    def solve(self, input):
        hashes = input.split(' ')
        target = hashes[-1]
        reachable = False

        set = set(hashes)

        for i in range(len(hashes) - 1):
            if len(hashes[i]) == 40 and len(target) == 40:
                if hashes[i] == target:
                    reachable = True
                    break

        if target in set:
            reachable = True

        return reachable
